To open a Google search within Visual Studio Code as a window that takes up half of your working space, you will need to use the Webview API to create a panel. This panel can be sized to take up half of the editor space.

Please note: It is important to ensure that your webview follows Visual Studio Code's content security policy and extension guidelines.

Here’s an updated version of the `extension.ts` file that demonstrates how to create a Webview panel for the Google search page:

```typescript
import * as vscode from 'vscode';

export function activate(context: vscode.ExtensionContext) {
    const disposable = vscode.commands.registerCommand('googleInVscode.openGoogle', () => {
        // Create and show a new webview
        const panel = vscode.window.createWebviewPanel(
            'googleSearch', // Identifies the type of the webview. Used internally
            'Google Search', // Title of the webview panel displayed to the user
            vscode.ViewColumn.Beside, // Opens the webview to the side of the current editor
            {} // Webview options. More can be added here.
        );

        // Set the webview's html content
        panel.webview.html = getWebviewContent();
    });

    context.subscriptions.push(disposable);
}

export function deactivate() {}

// Define the HTML content to load in the webview
function getWebviewContent() {
    return `
        <!DOCTYPE html>
        <html lang="en">
        <head>
            <meta charset="UTF-8">
            <meta name="viewport" content="width=device-width, initial-scale=1.0">
            <title>Google Search</title>
        </head>
        <body>
            <iframe src="https://www.google.com" frameborder="0" style="width:100%; height:100vh;"></iframe>
        </body>
        </html>
    `;
}
```

Make sure the `package.json` file of your extension declares the Webview API usage and command correctly. 

Here is the relevant portion of the `package.json` file:

```json
{
  //... (other settings)
  "activationEvents": [
    "onCommand:googleInVscode.openGoogle"
  ],
  "contributes": {
    "commands": [
      {
        "command": "googleInVscode.openGoogle",
        "title": "Open Google Search"
      }
    ]
  }
  //... (other settings)
}
```

